class LUT:
    """Simulates a k-input Look-Up Table."""
    def __init__(self, k: int, truth_table: int):
        self.k = k
        self.num_entries = 1 << k
        self.truth_table = truth_table & ((1 << self.num_entries) - 1)

    def evaluate(self, inputs: int) -> int:
        assert 0 <= inputs < self.num_entries, f"Input {inputs} out of range [0, {self.num_entries})"
        return (self.truth_table >> inputs) & 1

    @classmethod
    def from_function(cls, k: int, func):
        truth_table = 0
        for i in range(1 << k):
            if func(i):
                truth_table |= (1 << i)
        return cls(k, truth_table)

    def truth_table_bits(self) -> list:
        return [(self.truth_table >> i) & 1 for i in range(self.num_entries)]


def chain_luts(lut_a, lut_b, lut_combine):
    def evaluate(inputs):
        mask_a = (1 << lut_a.k) - 1
        in_a = inputs & mask_a
        in_b = (inputs >> lut_a.k) & ((1 << lut_b.k) - 1)
        out_a = lut_a.evaluate(in_a)
        out_b = lut_b.evaluate(in_b)
        combined_input = out_a | (out_b << 1)
        return lut_combine.evaluate(combined_input)
    return evaluate


def count_ones_circuit(n: int):
    luts_used = []

    def popcount(val, bits):
        """Recursively count ones using LUT tree."""
        if bits <= 6:
            lut = LUT.from_function(bits, lambda x: bin(x).count('1'))
            luts_used.append(lut)
            count = lut.evaluate(val)
            return count

        half = bits // 2
        mask_low = (1 << half) - 1
        low_val = val & mask_low
        high_val = (val >> half) & ((1 << (bits - half)) - 1)

        count_low = popcount(low_val, half)
        count_high = popcount(high_val, bits - half)
        return count_low + count_high

    def evaluate_func(input_bits):
        luts_used.clear()
        return popcount(input_bits, n)

    # Pre-populate luts_used with a dry run
    evaluate_func(0)
    saved_luts = list(luts_used)

    def final_eval(input_bits):
        return popcount(input_bits, n)

    return saved_luts, final_eval

class FIFO:
    def __init__(self, depth: int, width: int):
        assert depth > 0 and (depth & (depth - 1)) == 0, "Depth must be power of 2"
        self.depth = depth
        self.width = width
        self.mask = (1 << width) - 1
        self.addr_bits = depth.bit_length() - 1
        self.ptr_mask = (1 << (self.addr_bits + 1)) - 1  # includes MSB
        self.addr_mask = (1 << self.addr_bits) - 1
        self.mem = [0] * depth
        self.wr_ptr = 0
        self.rd_ptr = 0

    @property
    def is_empty(self) -> bool:
        return self.wr_ptr == self.rd_ptr

    @property
    def is_full(self) -> bool:
        return ((self.wr_ptr & self.addr_mask) == (self.rd_ptr & self.addr_mask) and
                (self.wr_ptr & ~self.addr_mask) != (self.rd_ptr & ~self.addr_mask))

    @property
    def count(self) -> int:
        diff = (self.wr_ptr - self.rd_ptr) & self.ptr_mask
        return diff

    @property
    def capacity(self) -> int:
        return self.depth

    def write(self, data: int) -> bool:
        if self.is_full:
            return False
        self.mem[self.wr_ptr & self.addr_mask] = data & self.mask
        self.wr_ptr = (self.wr_ptr + 1) & self.ptr_mask
        return True

    def read(self):
        if self.is_empty:
            return (False, 0)
        data = self.mem[self.rd_ptr & self.addr_mask]
        self.rd_ptr = (self.rd_ptr + 1) & self.ptr_mask
        return (True, data)

    def peek(self) -> int:
        if self.is_empty:
            return 0
        return self.mem[self.rd_ptr & self.addr_mask]


def simulate_scenario():
    fifo = FIFO(depth=8, width=16)
    writes = 0
    reads = 0
    drops = 0
    max_fill = 0
    read_data = []

    for cycle in range(30):
        # Producer writes every cycle
        data = cycle * 10 + 1
        if fifo.write(data):
            writes += 1
        else:
            drops += 1

        # Consumer reads every 3 cycles
        if cycle % 3 == 2:
            success, val = fifo.read()
            if success:
                reads += 1
                read_data.append(val)

        fill = fifo.count
        if fill > max_fill:
            max_fill = fill

    return {
        'writes': writes,
        'reads': reads,
        'drops': drops,
        'max_fill': max_fill,
        'read_data': read_data
    }

