import math

class ResourceEstimator:
    DEVICES = {
        'versal_vc1902': {
            'luts': 899_840,
            'ffs': 1_799_680,
            'brams': 967,
            'dsps': 1_968,
            'name': 'AMD Versal VC1902 (AI Core)'
        },
        'versal_vp1902': {
            'luts': 8_460_288,
            'ffs': 16_920_576,
            'brams': 6_814,
            'dsps': 6_864,
            'name': 'AMD Versal VP1902 (Premium)'
        },
        'agilex_agf027': {
            'luts': 912_800,
            'ffs': 3_651_200,
            'brams': 14_720,
            'dsps': 8_528,
            'name': 'Intel Agilex 7 F-Series AGF027'
        }
    }

    def estimate_component(self, comp_type: str, params: dict) -> dict:
        luts = 0
        ffs = 0
        brams = 0
        dsps = 0
        count = params.get('count', 1)

        if comp_type == 'logic_gate':
            inputs = params['inputs']
            luts_per = max(1, math.ceil(inputs / 6))
            luts = luts_per * count

        elif comp_type == 'register':
            width = params['width']
            ffs = width * count

        elif comp_type == 'counter':
            width = params['width']
            ffs = width * count
            luts = width * count  # increment logic

        elif comp_type == 'memory':
            depth = params['depth']
            width = params['width']
            total_bits = depth * width
            if total_bits <= 64:
                luts = max(1, math.ceil(total_bits / 64)) * count
            elif total_bits <= 36864:
                brams = 1 * count
            else:
                brams = math.ceil(total_bits / 36864) * count

        elif comp_type == 'multiplier':
            width = params['width']
            if width <= 27:
                dsps = 1 * count
            elif width <= 54:
                dsps = 2 * count
            else:
                dsps = math.ceil(width / 27) * count

        elif comp_type == 'fifo':
            depth = params['depth']
            width = params['width']
            # Memory for FIFO storage
            mem_est = self.estimate_component('memory', {'depth': depth, 'width': width, 'count': 1})
            brams = mem_est['brams'] * count
            luts_mem = mem_est['luts'] * count
            # Pointer registers (2 pointers, each log2(depth)+1 bits)
            ptr_bits = (depth.bit_length()) * 2
            ffs = (ptr_bits + width) * count  # pointers + output register
            luts = (luts_mem + ptr_bits + 10) * count  # pointers + control logic

        return {'luts': luts, 'ffs': ffs, 'brams': brams, 'dsps': dsps}

    def estimate_design(self, components: list) -> dict:
        total = {'luts': 0, 'ffs': 0, 'brams': 0, 'dsps': 0}
        for comp_type, params in components:
            est = self.estimate_component(comp_type, params)
            for key in total:
                total[key] += est[key]
        return total

    def check_fit(self, resources: dict, device: str) -> dict:
        dev = self.DEVICES[device]
        lut_pct = (resources['luts'] / dev['luts']) * 100
        ff_pct = (resources['ffs'] / dev['ffs']) * 100
        bram_pct = (resources['brams'] / dev['brams']) * 100
        dsp_pct = (resources['dsps'] / dev['dsps']) * 100
        fits = all(pct <= 100.0 for pct in [lut_pct, ff_pct, bram_pct, dsp_pct])
        return {
            'fits': fits,
            'lut_pct': round(lut_pct, 2),
            'ff_pct': round(ff_pct, 2),
            'bram_pct': round(bram_pct, 2),
            'dsp_pct': round(dsp_pct, 2),
            'device_name': dev['name']
        }
